import "./Products.css";

export default function ProductCard({ product, onCustomize }) {
  return (
    <div className="product-card" onClick={onCustomize}>
      <div className="card-img-wrap">
        <span className="card-emoji">{product.emoji}</span>
        <div className="card-overlay">
          <span className="card-overlay-text">Customize Now ✨</span>
        </div>
      </div>
      <div className="card-body">
        <div className="card-top-row">
          <div className="card-title">{product.name}</div>
          <div className="card-price">₹{product.price}</div>
        </div>
        <div className="card-desc">{product.desc}</div>
        <div className="card-features">
          {product.features.slice(0, 2).map(f => (
            <span className="card-feature-chip" key={f}>✓ {f}</span>
          ))}
        </div>
        <span className="card-tag">{product.tag}</span>
      </div>
    </div>
  );
}
